import React, {useEffect, useState} from 'react';
import type {FieldValues} from 'react-hook-form';
import type {Shapes, UseFieldLogicElementProps} from "@lmb/kitsconcerto-types";
import {uniqueId} from "lodash";
import {FormSelect} from "../../../../../";
import type {IListItem} from "@lmb/kitsconcerto-types";

export const Select = <T extends FieldValues>({
                                                  element,
                                                  control,
                                                  getValues,
                                                  fieldLogic,
                                              }: UseFieldLogicElementProps<T>) => {

    const [elementKey, setElementKey] = useState<string>(uniqueId(element.id.toString()));
    const {
        field,
        fieldState,
        label,
        placeholder,
        isDisabled,
        isRequired,
        helperText,
        watchedValues,
        list,
        attached,
    } = fieldLogic;

    // A simple, clean mapping from your element `type` to the underlying component's `shape`.
    const shapeMap: Record<string, Shapes> = {
        Select: 'dropdown',
        Multiselect: 'multiselect',
        Tags: 'autocomplete',
        ListBox: 'listBox',
        TreeSelect: 'treeSelect',
    };

    const shape: Shapes = shapeMap[element.type as keyof typeof shapeMap] || 'dropdown';

    // Destructure all possible specific props from the element.
    // Thanks to the discriminated union, only the relevant ones will have values.
    const {
        // Common
        labelKey,
        valueKey,
        outputValueKey,
        childrenKey,
        withFilter,
        filterBy,
        virtualScroll,
        // Specific
        withArrow,
        isMultiple,
        forceSelection,
        completeMethod,
        valueMode,
        selectionLimit,
        hideError,
        // TreeSelect specific
        onlyParentsWithChildren,
        isStructured,
    } = element as any; // Cast to any to easily access all possible props


    useEffect(() => {
        setElementKey(uniqueId(element.id.toString()));
    }, [list]);


    return (
        <FormSelect
            // --- Core & Resolved Props ---
            {...field}
            key={elementKey}
            id={field.name}
            shape={shape}
            label={label}
            placeholder={placeholder}
            disabled={isDisabled}
            required={isRequired}
            invalid={fieldState.invalid}
            errors={fieldState.error?.message}
            helperText={helperText}
            list={list as IListItem[]}
            hideError={hideError}
            attached={attached}
            // --- Specific Props Spread from Element ---
            // This works because the discriminated union ensures only the correct props are present
            labelKey={labelKey}
            valueKey={valueKey}
            outputValueKey={outputValueKey}
            childrenKey={childrenKey}
            withFilter={withFilter}
            filterBy={filterBy}
            virtualScroll={virtualScroll}
            withArrow={withArrow}
            isMultiple={isMultiple}
            forceSelection={forceSelection}
            completeMethod={completeMethod}
            valueMode={valueMode}
            selectionLimit={selectionLimit}
            onlyParentsWithChildren={onlyParentsWithChildren}
            isStructured={isStructured}
        />
    );
};

export default Select;
